    {"id":"avalokiteshvara","primary_name":"Avalokiteshvara","alternate_names":["Chenrezig (Tibetan)","Guanyin (Chinese)","Kannon (Japanese)"],"tradition_id":"buddhist","earliest_attestation":"Lotus Sutra c. 1st–2nd c. CE","primary_sources":["Lotus Sutra ch. 25","Karandavyuha Sutra","Heart Sutra"],"summary":"Bodhisattva of Infinite Compassion. Hears the cries of all suffering beings. Feminized in China as Guanyin. Every Dalai Lama held to be his emanation.","facets":["avalokiteshvara-compassion","avalokiteshvara-guanyin-feminine"]},
