    {"id":"three-pure-ones","primary_name":"The Three Pure Ones (Sanqing)","alternate_names":["Sanqing","Three Heavenly Worthies"],"tradition_id":"taoist","earliest_attestation":"c. 4th–6th c. CE Shangqing/Lingbao Taoism","primary_sources":["Daozang texts"],"summary":"Highest deities of organized Taoism. Yuanshi Tianzun (Primordial Beginning), Lingbao Tianzun (Numinous Treasure), Daode Tianzun (Way-and-Virtue — divinized Laozi). Triad parallel to Trimurti and Trinity.","facets":["three-pure-ones-triad","yuanshi-tianzun-primordial"]},
    {"id":"jade-emperor","primary_name":"The Jade Emperor (Yu Huang)","alternate_names":["Yuhuang Shangdi"],"tradition_id":"taoist","earliest_attestation":"Folk development; codified Song dynasty","primary_sources":["Folk religion","Song-Qing imperial rituals"],"summary":"Supreme administrator of the celestial bureaucracy. Cosmos organized as imperial court — subordinate gods govern domains, file reports, follow procedures.","facets":["jade-emperor-celestial-bureaucrat"]},
    {"id":"celestial-bureaucracy","primary_name":"The Celestial Bureaucracy","alternate_names":["gods of folk religion"],"tradition_id":"taoist","earliest_attestation":"Tang-Song dynasty onward","primary_sources":["Folk religion compendia"],"summary":"Below the Jade Emperor: City Gods, Kitchen God, Earth God, River/Mountain Gods, Eight Immortals, King of Hell. Each has specific jurisdiction. Chinese 'archon/lesser ruler' tier as imperial officials rather than tyrants.","facets":["celestial-bureaucracy-officials"]},
